// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract Probe {
    uint256 public value;

    modifier nonZero(uint256 newValue) {
        if (newValue == 0) {
            revert();
        }
        _;
    }

    function set(uint256 newValue) public nonZero(newValue) {
        value = newValue;
    }
}
